import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  BigInt: 'bigint',
  Bytes: 'Buffer',
}

/**
 * Maps a Prisma DMMF field type to a TypeScript type string.
 * Relation fields (kind === 'object') are omitted from REST interfaces.
 */
export function mapFieldToTsType(field: Field): string | null {
  if (field.kind === 'object') {
    return null
  }

  let tsType: string
  if (field.kind === 'enum') {
    tsType = field.type
  } else {
    tsType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired) {
    tsType = `${tsType} | null`
  }

  return tsType
}

