import type { Field, Model } from '@prisma/dmmf'

import { mapFieldToTsType } from './type-mapper'

interface FieldEntry {
  name: string
  tsType: string
  isRequired: boolean
  isId: boolean
  hasDefault: boolean
  isUpdatedAt: boolean
  isReadOnly: boolean
}

function collectScalarFields(model: Model): FieldEntry[] {
  const entries: FieldEntry[] = []
  for (const field of model.fields) {
    const tsType = mapFieldToTsType(field)
    if (tsType === null) continue
    entries.push({
      name: field.name,
      tsType,
      isRequired: field.isRequired,
      isId: field.isId,
      hasDefault: field.hasDefaultValue,
      isUpdatedAt: field.isUpdatedAt ?? false,
      isReadOnly: field.isReadOnly,
    })
  }
  return entries
}

function isAutoField(entry: FieldEntry): boolean {
  return entry.isId && entry.hasDefault
}

function isAutoManagedField(entry: FieldEntry): boolean {
  return entry.isUpdatedAt || isAutoField(entry)
}

function findIdFields(model: Model): Field[] {
  if (model.primaryKey) {
    return model.primaryKey.fields.map((name) => {
      const field = model.fields.find((f) => f.name === name)
      if (!field) throw new Error(`Primary key field "${name}" not found in model "${model.name}"`)
      return field
    })
  }
  const idField = model.fields.find((f) => f.isId)
  return idField ? [idField] : []
}

/** Generates the full model interface representing a database row. */
function generateModelInterface(name: string, fields: FieldEntry[]): string {
  const props = fields.map((f) => `  ${f.name}: ${f.tsType}`).join('\n')
  return `export interface ${name} {\n${props}\n}`
}

/** Generates the create input type, omitting auto-generated fields. */
function generateCreateInput(name: string, fields: FieldEntry[]): string {
  const props = fields
    .map((f) => {
      if (isAutoManagedField(f)) return null
      const optional = !f.isRequired || f.hasDefault ? '?' : ''
      return `  ${f.name}${optional}: ${f.tsType}`
    })
    .filter(Boolean)
    .join('\n')

  return `export interface ${name}CreateInput {\n${props}\n}`
}

/** Generates the update input type, where all fields are optional. */
function generateUpdateInput(name: string, fields: FieldEntry[]): string {
  const props = fields
    .filter((f) => !isAutoManagedField(f))
    .map((f) => `  ${f.name}?: ${f.tsType}`)
    .join('\n')

  return `export interface ${name}UpdateInput {\n${props}\n}`
}

/** Generates a unique identifier type for findUnique/update/delete. */
function generateWhereUniqueInput(name: string, idFields: Field[]): string {
  if (idFields.length === 0) {
    return `export type ${name}WhereUniqueInput = Record<string, unknown>`
  }

  const props = idFields
    .map((f) => {
      const tsType = mapFieldToTsType(f) ?? 'unknown'
      return `  ${f.name}: ${tsType}`
    })
    .join('\n')

  return `export interface ${name}WhereUniqueInput {\n${props}\n}`
}

/** Generates all types and CRUD methods for a single model. */
export function generateModel(model: Model): string {
  const fields = collectScalarFields(model)
  const idFields = findIdFields(model)
  const name = model.name
  const nameLower = name.charAt(0).toLowerCase() + name.slice(1)

  const sections = [
    generateModelInterface(name, fields),
    generateCreateInput(name, fields),
    generateUpdateInput(name, fields),
    generateWhereUniqueInput(name, idFields),
    generateCrudMethods(name, nameLower),
  ]

  return sections.join('\n\n')
}

function generateCrudMethods(name: string, nameLower: string): string {
  return `export interface ${name}Client {
  /** Retrieve all ${name} records, with optional query parameters. */
  findMany(params?: Record<string, unknown>): Promise<${name}[]>

  /** Retrieve a single ${name} by its unique identifier. */
  findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null>

  /** Create a new ${name} record. */
  create(data: ${name}CreateInput): Promise<${name}>

  /** Update an existing ${name} record. */
  update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}>

  /** Delete a ${name} record. */
  delete(where: ${name}WhereUniqueInput): Promise<${name}>
}`
}

