import type { Document } from '@prisma/dmmf'

import { generateEnum } from './generate-enum'
import { generateModel } from './generate-model'

/** Generates the complete REST API client source from a DMMF document. */
export function generateRestApiClient(dmmf: Document): string {
  const sections: string[] = []

  sections.push(generateHeader())

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModel(model))
  }

  sections.push(generateRestApiClientClass(dmmf))

  return sections.join('\n\n') + '\n'
}

function generateHeader(): string {
  return `// Generated by @prisma/rest-api-generator — do not edit manually.

/** Options for configuring the REST API client. */
export interface RestApiClientOptions {
  /** Base URL of the REST API server (e.g. "https://api.example.com"). */
  baseUrl: string

  /** Optional headers to include with every request. */
  headers?: Record<string, string>

  /** Optional custom fetch implementation. */
  fetch?: typeof globalThis.fetch
}`
}

function generateRestApiClientClass(dmmf: Document): string {
  const models = dmmf.datamodel.models

  const propertyDeclarations = models
    .map((m) => {
      const nameLower = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `  readonly ${nameLower}: ${m.name}Client`
    })
    .join('\n')

  const propertyInitializers = models
    .map((m) => {
      const nameLower = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      const endpoint = `/${nameLower}`
      return `    this.${nameLower} = {
      findMany: (params) => this.#request('GET', '${endpoint}', undefined, params),
      findUnique: (where) => this.#request('GET', \`${endpoint}/\${this.#encodeId(where)}\`),
      create: (data) => this.#request('POST', '${endpoint}', data),
      update: (where, data) => this.#request('PUT', \`${endpoint}/\${this.#encodeId(where)}\`, data),
      delete: (where) => this.#request('DELETE', \`${endpoint}/\${this.#encodeId(where)}\`),
    }`
    })
    .join('\n\n')

  return `/** Typed REST API client with CRUD methods for each model. */
export class RestApiClient {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>
  readonly #fetch: typeof globalThis.fetch

${propertyDeclarations}

  constructor(options: RestApiClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/+$/, '')
    this.#headers = {
      'Content-Type': 'application/json',
      ...options.headers,
    }
    this.#fetch = options.fetch ?? globalThis.fetch.bind(globalThis)

${propertyInitializers}
  }

  async #request<T>(method: string, path: string, body?: unknown, params?: Record<string, unknown>): Promise<T> {
    let url = \`\${this.#baseUrl}\${path}\`
    if (params) {
      const searchParams = new URLSearchParams()
      for (const [key, value] of Object.entries(params)) {
        if (value !== undefined) {
          searchParams.set(key, String(value))
        }
      }
      const qs = searchParams.toString()
      if (qs) {
        url = \`\${url}?\${qs}\`
      }
    }

    const response = await this.#fetch(url, {
      method,
      headers: this.#headers,
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })

    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText} for \${method} \${path}\`)
    }

    return response.json() as Promise<T>
  }

  #encodeId(where: Record<string, unknown>): string {
    const values = Object.values(where)
    if (values.length === 1) {
      return encodeURIComponent(String(values[0]))
    }
    return encodeURIComponent(JSON.stringify(where))
  }
}`
}

