      findUnique: (where) => this.#request('GET', \`${endpoint}/\${this.#encodeId(where)}\`),
      create: (data) => this.#request('POST', '${endpoint}', data),
      update: (where, data) => this.#request('PUT', \`${endpoint}/\${this.#encodeId(where)}\`, data),
      delete: (where) => this.#request('DELETE', \`${endpoint}/\${this.#encodeId(where)}\`),
    }`
    })
