import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateRestApiClient } from './generate-client'

/** Prisma generator that outputs a typed REST API client with CRUD methods for each model. */
export class RestApiGenerator implements Generator {
  readonly name = 'rest-api-generator'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      defaultOutput: config.output ? parseEnvValue(config.output) : './generated/rest-api-client',
      prettyName: 'Prisma REST API Client',
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const fs = await import('node:fs/promises')
    const path = await import('node:path')

    const outputDir = options.generator.output ? parseEnvValue(options.generator.output) : './generated/rest-api-client'

    await fs.mkdir(outputDir, { recursive: true })

    const source = generateRestApiClient(options.dmmf)
    const outputPath = path.join(outputDir, 'index.ts')
    await fs.writeFile(outputPath, source, 'utf-8')
  }
}

