import type { Field } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { mapFieldToTsType } from '../type-mapper'

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'test',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

describe('mapFieldToTsType', () => {
  test('maps String to string', () => {
    expect(mapFieldToTsType(makeField({ type: 'String' }))).toBe('string')
  })

  test('maps Int to number', () => {
    expect(mapFieldToTsType(makeField({ type: 'Int' }))).toBe('number')
  })

  test('maps Float to number', () => {
    expect(mapFieldToTsType(makeField({ type: 'Float' }))).toBe('number')
  })

  test('maps Boolean to boolean', () => {
    expect(mapFieldToTsType(makeField({ type: 'Boolean' }))).toBe('boolean')
  })

  test('maps DateTime to string', () => {
    expect(mapFieldToTsType(makeField({ type: 'DateTime' }))).toBe('string')
  })

  test('maps BigInt to bigint', () => {
    expect(mapFieldToTsType(makeField({ type: 'BigInt' }))).toBe('bigint')
  })

  test('maps Json to unknown', () => {
    expect(mapFieldToTsType(makeField({ type: 'Json' }))).toBe('unknown')
  })

  test('maps Decimal to string', () => {
    expect(mapFieldToTsType(makeField({ type: 'Decimal' }))).toBe('string')
  })

  test('maps Bytes to Buffer', () => {
    expect(mapFieldToTsType(makeField({ type: 'Bytes' }))).toBe('Buffer')
  })

  test('returns null for relation fields', () => {
    expect(mapFieldToTsType(makeField({ kind: 'object', type: 'User' }))).toBeNull()
  })

  test('maps enum fields to their type name', () => {
    expect(mapFieldToTsType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('appends [] for list fields', () => {
    expect(mapFieldToTsType(makeField({ type: 'String', isList: true }))).toBe('string[]')
  })

  test('appends | null for optional fields', () => {
    expect(mapFieldToTsType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('handles optional list fields', () => {
    expect(mapFieldToTsType(makeField({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })
})

