import { generateRestApiClient } from '../generate-client'

function makeDmmf(overrides: Partial<Document['datamodel']> = {}): Document {
  return {
    datamodel: {
      models: [],
      enums: [],
      types: [],
      indexes: [],
      ...overrides,
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  } as unknown as Document
}

describe('generateRestApiClient', () => {
  test('generates header with RestApiClientOptions', () => {
    const result = generateRestApiClient(makeDmmf())
    expect(result).toContain('export interface RestApiClientOptions')
    expect(result).toContain('baseUrl: string')
  })

  test('generates enum types as string unions', () => {
    const result = generateRestApiClient(
      makeDmmf({
        enums: [
          {
            name: 'Role',
            values: [
              { name: 'ADMIN', dbName: null },
              { name: 'USER', dbName: null },
            ],
          },
        ],
      }),
    )
    expect(result).toContain("export type Role =\n  | 'ADMIN'\n  | 'USER'")
  })

  test('generates model interface with correct field types', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'scalar',
                name: 'email',
                isRequired: true,
                isList: false,
                isUnique: true,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
              {
                kind: 'scalar',
                name: 'name',
                isRequired: false,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name: string | null')
  })

  test('generates CreateInput omitting auto-increment id', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'scalar',
                name: 'title',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface PostCreateInput {')
    expect(result).not.toMatch(/PostCreateInput[\s\S]*?\bid\b.*?:/)
    expect(result).toContain('  title: string')
  })

  test('generates UpdateInput with all fields optional', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'scalar',
                name: 'title',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface PostUpdateInput {')
    expect(result).toContain('  title?: string')
  })

  test('generates WhereUniqueInput from id field', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('  id: number')
  })

  test('generates CRUD client interface for each model', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface UserClient {')
    expect(result).toContain('findMany(params?: Record<string, unknown>): Promise<User[]>')
    expect(result).toContain('findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(result).toContain('create(data: UserCreateInput): Promise<User>')
    expect(result).toContain('update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(result).toContain('delete(where: UserWhereUniqueInput): Promise<User>')
  })

  test('generates RestApiClient class with model properties', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('readonly user: UserClient')
    expect(result).toContain('readonly post: PostClient')
    expect(result).toContain('constructor(options: RestApiClientOptions)')
  })

  test('omits relation fields from interfaces', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'object',
                name: 'posts',
                isRequired: false,
                isList: true,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'Post',
                hasDefaultValue: false,
                relationName: 'UserPosts',
                relationFromFields: [],
                relationToFields: [],
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface User {')
    expect(result).not.toMatch(/User \{[\s\S]*?posts/)
  })

  test('handles composite primary key', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'PostTag',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'postId',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: false,
              },
              {
                kind: 'scalar',
                name: 'tagId',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: { name: null, fields: ['postId', 'tagId'] },
          },
        ],
      }),
    )

    expect(result).toContain('export interface PostTagWhereUniqueInput {')
    expect(result).toContain('  postId: number')
    expect(result).toContain('  tagId: number')
  })

  test('handles updatedAt fields by omitting from create/update inputs', () => {
    const result = generateRestApiClient(
      makeDmmf({
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'scalar',
                name: 'updatedAt',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'DateTime',
                hasDefaultValue: false,
                isUpdatedAt: true,
              },
              {
                kind: 'scalar',
                name: 'title',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
      }),
    )

    expect(result).toContain('export interface PostCreateInput {')
    expect(result).not.toMatch(/PostCreateInput[\s\S]*?updatedAt/)
    expect(result).not.toMatch(/PostUpdateInput[\s\S]*?updatedAt/)
  })
})

